// Simulate what cli.js context does:
// 1. Get ranked results from Qdrant (mocked)
const mockHits = [
  { score: 0.95, content: 'Best practices for web development include using semantic HTML, proper ARIA labels, keyboard navigation support, and responsive design patterns.', summary: '', source: 'docs/web.md', type: 'research' },
  { score: 0.88, content: 'Accessibility guidelines (WCAG 2.1) require color contrast ratios of at least 4.5:1 for normal text, proper focus indicators, and screen reader compatibility.', summary: '', source: 'docs/accessibility.md', type: 'research' },
  { score: 0.82, content: 'Performance optimization techniques include lazy loading images, code splitting, caching strategies, and minimizing bundle size through tree shaking.', summary: '', source: 'src/performance.js', type: 'code' }
];

// Map to result objects (like cli.js does)
let rankedResults = mockHits.map(hit => ({ ...hit.payload || hit, score: hit.score, _query: 'best practices web development' }));

// Apply recency boost and path matching re-ranking
applyRecencyBoost(rankedResults);

// Sort by updated score descending and limit to 5 results  
const ranked = rankedResults.sort((a, b) => b.score - a.score).slice(0, 5);

console.log('--- Before token estimation ---');
let totalTokens = 0;
for (const r of ranked) {
  const textFields = [r.content, r.summary, r.text].filter(Boolean);
  for (const field of textFields) {
    totalTokens += estimateTokens(field);
  }
}
console.log('Total estimated tokens:', totalTokens);

// Trim if over budget
let trimmedInfo;
try {
  trimmedInfo = trimResultsByTokenBudget(ranked, { maxTokens: 4000 });
} catch (_) {}

if (trimmedInfo && trimmedInfo.trimmed) {
  console.log('[retrieval] %d results, ~%d estimated tokens, trimmed to 500 chars per result', ranked.length, totalTokens);
} else {
  console.log('[retrieval] %d results, ~%d estimated tokens (under budget)', ranked.length, totalTokens);
}

// Clean up internal flag
for (const r of ranked) { if (r && '_truncated' in r) delete r._truncated; }

console.log('--- Output JSON ---');
console.log(JSON.stringify({ query: 'best practices web development', project_id: 'test-project', results: ranked }, null, 2));
"

